input.command:
RUN_ID=$ZEALT_RUN_ID && curl -s -X POST "https://api.hookdeck.com/2025-07-01/connections" \
  -H "Authorization: Bearer $HOOKDECK_API_KEY" \
  -H "Content-Type: application/json" \
  -d "{
    \"name\": \"stripe-charge-succeeded-${RUN_ID}\",
    \"source\": {
      \"name\": \"stripe-src-${RUN_ID}\",
      \"type\": \"STRIPE\"
    },
    \"destination\": {
      \"name\": \"mock-dest-${RUN_ID}\",
      \"type\": \"MOCK_API\"
    },
    \"rules\": [
      {
        \"type\": \"filter\",
        \"body\": {
          \"type\": \"charge.succeeded\"
        }
      }
    ]
  }" | jq .

